+    // ── Core GFM features (br-3vwi.3.2) ──────────────────────────
+
+    #[test]
+    fn heading_levels_render() {
+        let md = "# H1\n## H2\n### H3\n#### H4\n##### H5\n###### H6";
+        let text = render_body(md, &theme());
+        assert!(text.height() >= 6, "All 6 heading levels should render");
+    }
+
+    #[test]
+    fn unordered_list_renders() {
